INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('8094bed4-5155-428d-a806-f0f7418d395f', '{"options": [{"answer": "A", "content": "No, never. I''m really excited.", "imageUrl": ""}, {"answer": "B", "content": "I''m not happy.", "imageUrl": ""}, {"answer": "C", "content": "In the forest near here.", "imageUrl": ""}, {"answer": "D", "content": "Me too! My dad says it will be sunny this weekend.", "imageUrl": ""}, {"answer": "E", "content": "We''re going camping.", "imageUrl": ""}, {"answer": "F", "content": "With my dad and my brother.", "imageUrl": ""}, {"answer": "G", "content": "Will you go in the sea?", "imageUrl": ""}, {"answer": "H", "content": "Thanks a lot.", "imageUrl": ""}], "groupImageUrl": "questions/images/1774395601627_b304a47f_q2_rw_part2_1.png"}', 1, '7', null, 'a0676e0b-eece-46cf-a80a-872952488fcc');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('60fe649f-a0a2-4c73-840a-64d297a4a368', '{"title": "My first day at school", "content": "My name''s Betty Stewart and I''m an English teacher. I was twenty-two years old when I got my first teaching job. I remember my first day very well!\n\nThe day didn''t start well. I got up early and got dressed. Then I dropped my cereal all over my new skirt. I quickly put on clean clothes. I picked up my bag and went to the bus stop. I saw a lot of people waiting for the bus. I asked a woman, \"Why are there so many people?\" She said \"There''s a lot of traffic in the city centre and all the buses are late.\" So, I decided to walk to school.\n\nI only had half an hour before my first lesson. I walked very quickly. After some time I could see the school at the end of the road. I felt very happy. Suddenly it started to rain. I ran fast but I was very wet when I arrived at school. When I got to my classroom I was five minutes late and I looked wet and horrible. At first, my new students looked surprised when they saw me. Then they all smiled and said, \"Good morning Miss Stewart!\" I smiled back and said \"Good morning class!\" After that, the day got much better.", "imageUrl": ""}', 1, '10', null, 'a0676e0b-eece-46cf-a80a-872952488fcc');
